import { useState } from 'react';
import './App.css';


const App = () => {
  let [cnt , setCnt] = useState(0);
  return(
    <div className="App">
      <h1>
        <button onClick={()=> setCnt(++cnt)} >+</button><br></br>
        {cnt}      <br></br>
        <button onClick={()=> setCnt(--cnt)} >-</button><br></br>
      </h1>
    </div>
  )
}

export default App;
